mapper.select:
SELECT 
FROM content

    deleted = 0

        AND title LIKE CONCAT('%', #{title}, '%')


        AND content_type = #{contentType}


        AND status = #{status}


        AND publish_status = #{publishStatus}


        AND author_id = #{authorId}


        AND category_id = #{categoryId}


        AND is_top = #{isTop}


        AND create_time >= #{startTime}


        AND create_time <= #{endTime}


ORDER BY

        publish_time DESC
        view_count DESC
        like_count DESC
        create_time DESC
